ans = {}
n = int(input())
for i in range(n):
    id,email = input().split(" ",1)
    email = email.strip()
    id = int(id)
    if email in ans:
        if ans[email] > id:
            ans[email] = id
    else:
        ans[email] = id

ans = sorted((i,j) for j,i in ans.items())
print(len(ans))
for i,j in ans:
    print(i,j)
